    bool reachingPoints(int sx, int sy, int tx, int ty) {
        while(tx>=sx && ty>=sy){
            if(tx==ty) break;
            if(tx>ty){ if(ty<sy) return false; if(tx>=ty*2LL) tx%=ty; else tx-=ty; }
            else { if(tx<sx) return false; if(ty>=tx*2LL) ty%=tx; else ty-=tx; }
